SELECT user_id, COUNT(request_id) AS request_count
FROM requests
GROUP BY user_id;

SELECT *
FROM requests
WHERE duration > (SELECT AVG(duration) FROM requests);

SELECT *
FROM endpoints
WHERE rate_limit > 1000;

SELECT group_by_id, group_by_name, description
FROM group_bys
WHERE group_by_name = 'user_id';

SELECT request_method, duration
FROM requests
ORDER BY duration DESC;
